inbound.log-to-eventhub:
@{
    return new JObject(
        new JProperty("ts",          DateTime.UtcNow.ToString("o")),
        new JProperty("requestId",   context.RequestId),
        new JProperty("subscription", context.Subscription?.Id ?? "anon"),
        new JProperty("api",         context.Api.Id),
        new JProperty("operation",   context.Operation.Id),
        new JProperty("method",      context.Request.Method),
        new JProperty("url",         context.Request.Url.ToString()),
        new JProperty("clientIp",    context.Request.IpAddress),
        new JProperty("userAgent",   context.Request.Headers.GetValueOrDefault("User-Agent","")),
        new JProperty("modelTier",   context.Request.Headers.GetValueOrDefault("x-model-tier","")),
        new JProperty("authMode",    context.Request.Headers.GetValueOrDefault("x-auth-mode","entra"))
    ).ToString(Newtonsoft.Json.Formatting.None);
}

outbound.log-to-eventhub:
@{
    return new JObject(
        new JProperty("ts",            DateTime.UtcNow.ToString("o")),
        new JProperty("requestId",     context.RequestId),
        new JProperty("statusCode",    context.Response.StatusCode),
        new JProperty("backend",       context.Variables.ContainsKey("targetBackend")
                                        ? (string)context.Variables["targetBackend"] : ""),
        new JProperty("tokensConsumed", context.Response.Headers.GetValueOrDefault("x-tokens-consumed","")),
        new JProperty("tokensRemaining",context.Response.Headers.GetValueOrDefault("x-tokens-remaining","")),
        new JProperty("cacheStatus",   context.Variables.ContainsKey("semantic-cache-result")
                                        ? (string)context.Variables["semantic-cache-result"] : "Miss"),
        new JProperty("durationMs",    context.Elapsed.TotalMilliseconds)
    ).ToString(Newtonsoft.Json.Formatting.None);
}

on-error.log-to-eventhub:
@{
    var err = context.LastError;
    return new JObject(
        new JProperty("ts",        DateTime.UtcNow.ToString("o")),
        new JProperty("requestId", context.RequestId),
        new JProperty("level",     "ERROR"),
        new JProperty("source",    err?.Source ?? ""),
        new JProperty("reason",    err?.Reason ?? ""),
        new JProperty("section",   err?.Section ?? ""),
        new JProperty("message",   err?.Message ?? ""),
        new JProperty("policyId",  err?.PolicyId ?? "")
    ).ToString(Newtonsoft.Json.Formatting.None);
}
